mapper.select:
SELECT cx.*
FROM chest_xray cx

    INNER JOIN sequence_image si ON si.image_id = cx.id AND si.seq_id = #{q.seqId}



        AND (cx.image_name LIKE CONCAT('%', #{q.keyword}, '%')
          OR cx.diseases LIKE CONCAT('%', #{q.keyword}, '%'))


        AND cx.diseases LIKE CONCAT('%', #{q.diseases}, '%')


        AND cx.image_name LIKE CONCAT('%', #{q.imageName}, '%')


        AND cx.label_str = #{q.labelStr}


        AND cx.patient_id = #{q.patientId}


        AND cx.patient_name LIKE CONCAT('%', #{q.patientName}, '%')


        AND cx.patient_id IN (
            SELECT p.patient_id FROM medical_patient p
            WHERE p.attending_doctor_id = #{q.attendingDoctorId}
        )


        AND cx.width >= #{q.minWidth}


        AND cx.width <= #{q.maxWidth}


        AND cx.create_time >= #{q.beginTime}


        AND cx.create_time <= #{q.endTime}


ORDER BY cx.create_time DESC
